<?php
$status=sanitize_text_field($_GET['status']??'');$where=$status?$wpdb->prepare('WHERE l.status=%s',$status):'';$rows=$wpdb->get_results("SELECT l.*,c.first_name,c.last_name FROM {$wpdb->prefix}ct_loans l JOIN {$wpdb->prefix}ct_clients c ON c.id=l.client_id $where ORDER BY l.created_at DESC LIMIT 50");$can_approve=current_user_can('creditrack_approve_loans')||(current_user_can('creditrack_create_loans')&&!empty($settings['officer_can_approve']));$can_disburse=current_user_can('creditrack_disburse_loans')||(current_user_can('creditrack_create_loans')&&!empty($settings['officer_can_disburse']));
?><div class="ct-titlebar"><h1>Loans</h1><?php if(current_user_can('creditrack_create_loans')){ ?><a class="ct-button" href="#loan-form">Create loan</a><?php } ?></div><div class="ct-table-wrap"><table><thead><tr><th>Loan</th><th>Borrower</th><th>Status</th><th>Principal</th><th>Paid</th><th>Outstanding</th><th>Actions</th></tr></thead><tbody><?php foreach($rows as $row){ $allowed_action=('Pending'===$row->status&&$can_approve)||('Approved'===$row->status&&$can_disburse); ?><tr><td><?php echo esc_html($row->loan_number); ?></td><td><?php echo esc_html("$row->first_name $row->last_name"); ?></td><td><span class="ct-badge <?php echo esc_attr(str_replace(' ','-',$row->status)); ?>"><?php echo esc_html($row->status); ?></span></td><td><?php echo esc_html($currency.number_format_i18n($row->principal,2)); ?></td><td><?php echo esc_html($currency.number_format_i18n($row->total_paid,2)); ?></td><td><?php echo esc_html($currency.number_format_i18n($row->outstanding,2)); ?></td><td><?php if($allowed_action){ ?><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><?php wp_nonce_field('creditrack_action'); ?><input type="hidden" name="action" value="creditrack_loan_action"><input type="hidden" name="loan_id" value="<?php echo esc_attr($row->id); ?>"><input type="hidden" name="loan_action" value="<?php echo $row->status==='Pending'?'approve':'disburse'; ?>"><button type="submit"><?php echo $row->status==='Pending'?'Approve':'Disburse'; ?></button></form><?php }elseif(in_array($row->status,array('Pending','Approved'),true)){ ?><span class="ct-muted">Administrator action required</span><?php } ?></td></tr><?php } if(!$rows){ ?><tr><td colspan="7">No loans found.</td></tr><?php } ?></tbody></table></div>
<?php if(current_user_can('creditrack_create_loans')){$clients=$wpdb->get_results("SELECT id,first_name,last_name FROM {$wpdb->prefix}ct_clients WHERE is_active=1 ORDER BY last_name");?><section id="loan-form" class="ct-card"><h2>Create loan</h2><form id="ct-loan-form" class="ct-form" method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><?php wp_nonce_field('creditrack_action'); ?><input type="hidden" name="action" value="creditrack_create_loan"><input type="hidden" name="idempotency_key" value="<?php echo esc_attr(wp_generate_uuid4()); ?>"><div class="ct-field"><label for="client_id">Client</label><select id="client_id" name="client_id" required><option value="">Select</option><?php foreach($clients as $client){?><option value="<?php echo esc_attr($client->id); ?>"><?php echo esc_html("$client->last_name, $client->first_name"); ?></option><?php } ?></select></div><?php $defaults=array('principal'=>'','interest_rate'=>$settings['default_interest_rate']??'15','term_months'=>$settings['default_term']??12,'guarantor'=>'','guarantor_phone'=>'');foreach(array('principal'=>'Principal','interest_rate'=>'Interest rate (%)','term_months'=>'Term (months)','guarantor'=>'Guarantor','guarantor_phone'=>'Guarantor phone') as $name=>$label){?><div class="ct-field"><label for="<?php echo esc_attr($name); ?>"><?php echo esc_html($label); ?></label><input id="<?php echo esc_attr($name); ?>" name="<?php echo esc_attr($name); ?>" value="<?php echo esc_attr($defaults[$name]); ?>" <?php echo in_array($name,array('principal','interest_rate','term_months'),true)?'required':''; ?>></div><?php } ?><div class="ct-field"><label for="interest_type">Calculation method</label><select id="interest_type" name="interest_type"><?php foreach(array('Amortized'=>'Declining balance (annual rate)','Flat'=>'Flat (whole-term rate)','Monthly'=>'Precomputed monthly rate','Quarterly'=>'Precomputed quarterly rate','Annual'=>'Precomputed annual rate') as $type=>$label){?><option value="<?php echo esc_attr($type); ?>" <?php selected($settings['default_interest_type']??'Amortized',$type); ?>><?php echo esc_html($label); ?></option><?php } ?></select></div><div class="ct-field full" data-loan-preview aria-live="polite">Enter loan terms to preview totals.</div><?php foreach(array('purpose'=>'Purpose','collateral'=>'Collateral','notes'=>'Notes') as $name=>$label){?><div class="ct-field full"><label for="<?php echo esc_attr($name); ?>"><?php echo esc_html($label); ?></label><textarea id="<?php echo esc_attr($name); ?>" name="<?php echo esc_attr($name); ?>"></textarea></div><?php } ?><div><button type="submit">Create loan</button></div></form></section><?php }
